const items = $input.all();
const propertyCode = items[0].json.property_code;
const propertyAddress = items[0].json.property_address;

const levelEmoji = {
  'Muy Alto': '🔥',
  'Alto': '⬆️',
  'Medio': '➡️',
  'Bajo': '⬇️'
};

let lines = [
  `👥 *Interesados - ${propertyCode}*`,
  `📍 ${propertyAddress}`,
  `Total: ${items.length} cliente(s)`,
  ''
];

items.forEach((item, i) => {
  const c = item.json;
  const emoji = levelEmoji[c.interest_level] || '•';
  const date = new Date(c.interest_date).toLocaleDateString('es-EC');
  lines.push(`${i + 1}. ${emoji} *${c.client_name}*`);
  lines.push(`   📞 ${c.phone}${c.email ? ' | ✉️ ' + c.email : ''}`);
  lines.push(`   Interés: ${c.interest_level} | Fecha: ${date}`);
  if (c.notes) lines.push(`   💬 ${c.notes}`);
  lines.push('');
});

return [{ json: { resultado: lines.join('\n') } }];
